def update_stock(db: Session, product_id: int, quantity_change: int):
    db_product = crud.get_product(db, product_id=product_id)
    if not db_product:
        raise HTTPException(status_code=404, detail="Product not found")
    db_stock = crud.get_stock_by_product(db, product_id=product_id)
    if not db_stock:
        db_stock = schemas.StockCreate(product_id=product_id, quantity=quantity_change)
        return crud.create_stock(db=db, stock=db_stock)
    else:
        new_quantity = db_stock.quantity + quantity_change
        if new_quantity < 0:
            raise HTTPException(status_code=400, detail="Stock cannot be negative")
        db_stock.quantity = new_quantity
        return crud.update_stock(db=db, stock_id=db_stock.id, stock=db_stock)

